#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long A;
        scanf("%lld", &A);
        long long a = 0, b = 1;
        while (b < A) {
            long long temp = a;
            a = b;
            b = temp + b;
        }
        if (b == A) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

