code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long A = sc.nextLong();
            long a = 0, b = 1;
            while (b < A) {
                long temp = a;
                a = b;
                b = temp + b;
            }
            if (b == A) System.out.println("YES");
            else System.out.println("NO");
        }
    }
}

